/// <summary>
/// extension class for table <c>ITMTmpCreatorTable</c>
/// </summary>
[ExtensionOf(tableStr(ITMTmpCreatorTable))]
public final class ETGITMTmpCreatorTable_Extension
{
}

Method.Source:
public static ITMTmpCreatorTable createOnServerOutboundETG()
{
    ITMTmpCreatorTable tmpShipCreatorTable;

    select tmpShipCreatorTable;

    return tmpShipCreatorTable;
}

/// <summary>
/// create temp data and lines for sales or transfer orders
/// </summary>
/// <param name = "_tmpShipCreatorTable">ITMTmpCreatorTable _tmpShipCreatorTable</param>
/// <param name = "_tmpShipCreatorLine">ITMTmpCreatorLine _tmpShipCreatorLine</param>
internal static void showSelectedOutboundETG(ITMTmpCreatorTable _tmpShipCreatorTable, ITMTmpCreatorLine _tmpShipCreatorLine)
{
    ITMTmpCreatorLine tmpShipCreatorLine;
    ITMTmpCreatorLine tmpShipCreatorLineUpdate;
    FormDataSource datasource = FormDataUtil::getFormDataSource(_tmpShipCreatorTable);
    ITMTmpCreatorTable tmpShipCreatorTableSelected;
    boolean isFirst = true;

    tmpShipCreatorLine.setTmpData(_tmpShipCreatorLine);
    tmpShipCreatorLineUpdate.setTmpData(_tmpShipCreatorLine);
    tmpShipCreatorTableSelected.setTmpData(_tmpShipCreatorTable);

    while select tmpShipCreatorLine
        group by InventTransRefId, InventTransType, DateStatus
        where tmpShipCreatorLine.Selected
    {
        select firstonly tmpShipCreatorTableSelected
            where tmpShipCreatorTableSelected.InventTransType == tmpShipCreatorLine.InventTransType
                && tmpShipCreatorTableSelected.InventTransRefId == tmpShipCreatorLine.InventTransRefId
                && tmpShipCreatorTableSelected.DateStatus == tmpShipCreatorLine.DateStatus
                && tmpShipCreatorTableSelected.InventSiteId == tmpShipCreatorLine.InventSiteId
                && tmpShipCreatorTableSelected.InventLocationId == tmpShipCreatorLine.InventLocationId
                && tmpShipCreatorTableSelected.ShipDataArea == tmpShipCreatorLine.ShipDataArea;

        if (tmpShipCreatorTableSelected.RecId)
        {
            if (isFirst)
            {
                isFirst = false;
                datasource.research();
            }

            datasource.markRecord(tmpShipCreatorTableSelected, true);

            while select forupdate tmpShipCreatorLineUpdate
                where tmpShipCreatorLineUpdate.InventTransType == tmpShipCreatorLine.InventTransType
                    && tmpShipCreatorLineUpdate.InventTransRefId == tmpShipCreatorLine.InventTransRefId
                    && tmpShipCreatorLineUpdate.DateStatus == tmpShipCreatorLine.DateStatus
                    && tmpShipCreatorLineUpdate.InventSiteId == tmpShipCreatorLine.InventSiteId
                    && tmpShipCreatorLineUpdate.InventLocationId == tmpShipCreatorLine.InventLocationId
                    && tmpShipCreatorLineUpdate.ShipDataArea == tmpShipCreatorLine.ShipDataArea
                    && tmpShipCreatorLineUpdate.HeaderMarked == NoYes::No
            {
                tmpShipCreatorLineUpdate.HeaderMarked = NoYes::Yes;
                tmpShipCreatorLineUpdate.update();
            }
        }
    }

    FormDataUtil::getFormDataSource(_tmpShipCreatorLine).research();
}
